  ('social-worker-moex-01954', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某地方政府社會局今年編列500萬，針對該縣市6歲以下幼兒進行發展遲緩篩選。經辦理30場次篩選活 動，計3,258人次檢查，幾乎達到預計人數，並篩選出205位疑似遲緩者，轉介相關單位接受相關處遇， 績效顯著較往年提升30%。依方案服務邏輯模式概念，以下敘述何者錯誤？', '["完成3,258人次屬於產出（output）", "編列500萬是屬於過程（thru-put）", "30%績效提升是效應（effect）", "篩選出205位疑似個案接受處遇是成果（outcome）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01955', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列有關社會服務「方案假設」敘述，何者錯誤？', '["方案主要於聚焦問題，並非活動", "方案假設可以將方案活動與成果連結在一起", "方案假設能夠作為長程規劃的基礎", "方案可作為分析成本效益之資料庫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01956', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '從社會服務方案的時間架構（time frames）而言，預期目標達成的三種層次成果，以下何者錯誤？', '["方案參與者初次經歷的利益或改變，屬初始成果", "參與者新學習的知識、態度、技能所致的行為改變，屬於中間成果", "方案預期參與者達成的最終成果，屬於長期成果", "衡量參與者的進展朝向目標的重要指標，指的是長期成果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01957', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在多元化的社會發展趨勢下，要求服務供給者具備多元文化能力，避免服務的社會排除。試問這項管控 服務品質的作法，比較偏向要確保下列何種特性？', '["同理性（empathy）", "保證性（assurance）", "回應性（responsiveness）", "公平性（equity）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01958', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志願服務人力是政府及民間非營利組織推展業務的重要資源之一。試問下列何者對「志願服務特質」的 描述較為適切？', '["志工是運用單位的免費人力資源", "強調利他且利己並重的雙利特質", "強調自由意志的選擇", "志工不能領取任何津貼"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01959', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當組織努力提供員工一個適當的工作環境及設施，以增進其組織認同，進而降低離職率。試問這個組織 比較偏向實踐下列那種人力資源管理功能？', '["維持（maintenance）", "激勵（motivation）", "培訓與發展（training and development）", "績效考核（evaluation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01960', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當社會工作者面臨處遇失當的「申訴」時，督導適時協助社會工作者釐清專業責任，並一起完成答辯書 的撰寫，以完成服務責信工作。試問督導比較側重執行下列何種督導功能？', '["支持性功能", "調解性功能", "行政性功能", "教育性功能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
